using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateSampleItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product {i}",
                Price = 10m * i,
                Quantity = i
            })
            .ToList();

    #region CreateOrder

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithCorrectProperties()
    {
        // Arrange
        var customerId = "cust-1";
        var items = CreateSampleItems(2);

        // Act
        var order = _service.CreateOrder(customerId, items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual(customerId, order.CustomerId);
        Assert.AreEqual(items, order.Items);
        Assert.IsNotNull(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_CalculatesTotalCorrectly()
    {
        // Arrange — items: (10*1) + (20*2) = 50
        var items = CreateSampleItems(2);

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateSampleItems();

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, CreateSampleItems()));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var created = _service.CreateOrder("cust-1", CreateSampleItems());

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistingId_ReturnsNull()
    {
        var result = _service.GetOrder("non-existent-id");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-unknown");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateSampleItems());
        _service.CreateOrder("cust-1", CreateSampleItems());
        _service.CreateOrder("cust-2", CreateSampleItems());

        // Act
        var result = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomerOrders()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateSampleItems());
        var otherOrder = _service.CreateOrder("cust-2", CreateSampleItems());

        // Act
        var result = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.DoesNotContain(otherOrder, result);
    }

    #endregion
}

